mapper.sql:
n.status = 'Y'
AND n.class_id = #{classId}
AND (
    (#{roleCode} = 'TEACHER' AND n.class_id IN (
        SELECT tc.class_id
        FROM teacher_class tc
        WHERE tc.teacher_id = #{memberId}
    ))
    OR
    (#{roleCode} = 'STUDENT' AND n.class_id IN (
        SELECT sc.class_id
        FROM student_class sc
        WHERE sc.student_id = #{memberId}
    ) AND n.target IN ('ALL', 'STUDENT'))
    OR
    (#{roleCode} = 'PARENT' AND n.class_id IN (
        SELECT sc.class_id
        FROM student_parent sp
        JOIN student_class sc ON sp.student_id = sc.student_id
        WHERE sp.parent_id = #{memberId}
    ) AND n.target IN ('ALL', 'PARENT'))
)

mapper.select:
SELECT MIN(class_id)
FROM teacher_class
WHERE teacher_id = #{memberId}

mapper.update:
UPDATE notice
SET status = 'N',
    updated_at = SYSDATE
WHERE notice_id = #{noticeId}
  AND class_id = #{classId}

