INSERT INTO attach (
    ano, pno, uploadpath, filename, filetype, attacher, regdate
) VALUES (
    (SELECT NVL(MAX(ano), 0) + 1 FROM attach),
    #{pno}, #{uploadPath}, #{fileName}, #{fileType}, #{attacher}, SYSDATE
)

mapper.select:
SELECT ano, pno, uploadpath, filename, filetype, attacher, regdate
FROM attach
WHERE ano = #{ano}
